sql:
SELECT owner_name
FROM farm_owners
WHERE is_active = 1;

SELECT SUM(amount) AS total_water_used
  FROM irrigation_records
  WHERE subarea_id = 1;

SELECT SUM(area) AS total_drip_irrigation_area
FROM subareas
WHERE irrigation_system_type = 'drip';

SELECT crop_name
FROM crop_rotation
WHERE subarea_id = 1 AND year = 2023;

SELECT soil_temperature
FROM soil_properties
WHERE subarea_id = 1;

SELECT SUM(crop_yield) AS total_yield
FROM crop_rotation
WHERE crop_name = 'Wheat' AND year = 2023;

SELECT subarea_name
FROM subareas
WHERE subarea_id = 1;

SELECT AVG(soil_temperature) AS avg_soil_temperature
FROM soil_properties
WHERE subarea_id = 1;
